curl -X POST "https://api.musiccloud.io/api/v1/resolve" \
  -H "X-API-Key: <api-key>" \
  -H "Content-Type: application/json" \
  -d '{
  "query": "https://open.spotify.com/track/2WfaOiMkCvy7F5fcp2zZ8L"
}'

const response = await fetch("https://api.musiccloud.io/api/v1/resolve", {
  method: "POST",
  headers: {
      "X-API-Key": "<api-key>",
      "Content-Type": "application/json"
  },
  body: JSON.stringify({
    "query": "https://open.spotify.com/track/2WfaOiMkCvy7F5fcp2zZ8L"
  }),
});
const data = await response.json();

