import Foundation

let url = URL(string: "https://api.musiccloud.io/api/v1/resolve")!
var request = URLRequest(url: url)
request.httpMethod = "POST"
request.setValue("<api-key>", forHTTPHeaderField: "X-API-Key")
request.setValue("application/json", forHTTPHeaderField: "Content-Type")
request.httpBody = try JSONSerialization.data(withJSONObject: ["query": "https://open.spotify.com/track/2WfaOiMkCvy7F5fcp2zZ8L"])

let (data, _) = try await URLSession.shared.data(for: request)
let json = try JSONSerialization.jsonObject(with: data)

